// N2 - Preparador (Prompt Assembly)
const input = $input.first().json;
const body = input.body || input;

const texto = body.texto;
const idioma = body.idioma_destino || 'EN';
const variante = body.variante || '';
const genero = body.genero || 'literário';
const glossario = body.glossario || {};
const autor = body.autor || 'Autor Desconhecido';
const obra = body.obra || 'Obra';
const capitulo = body.capitulo || 1;
const gerarCapa = body.gerar_capa || false;

if (!texto) {
  throw new Error('Campo "texto" é obrigatório');
}

const idiomas = {
  'EN': 'English', 'ES': 'Spanish', 'DE': 'German',
  'FR': 'French', 'ZH': 'Chinese', 'JA': 'Japanese',
  'KO': 'Korean', 'RU': 'Russian', 'AR': 'Arabic'
};

const nomeIdioma = idiomas[idioma] || idioma;
const isAsian = ['ZH', 'JA', 'KO'].includes(idioma);

let glossarioStr = '';
if (Object.keys(glossario).length > 0) {
  glossarioStr = '\nGLOSSÁRIO OBRIGATÓRIO:\n' +
    Object.entries(glossario).map(([k,v]) => `- "${k}" → "${v}"`).join('\n');
}

const prompt = `Você é um tradutor literário especializado em ${nomeIdioma}.
Obra: "${obra}" de ${autor}
Gênero: Realismo Regional Brasileiro
Capítulo: ${capitulo}
${variante ? `Variante: ${variante}` : ''}
${glossarioStr}

REGRAS:
1. Preservar ritmo e cadência do original
2. Manter registro coloquial onde apropriado
3. Adaptar expressões idiomáticas sem perder significado
4. Manter pontuação estilística do autor
5. NÃO adicionar notas ou comentários - retorne APENAS a tradução

TEXTO PARA TRADUZIR:
${texto}`;

return [{
  json: {
    prompt,
    texto_original: texto,
    idioma_destino: idioma,
    variante,
    genero,
    autor,
    obra,
    capitulo,
    gerar_capa: gerarCapa,
    glossario,
    is_asian: isAsian,
    timestamp: new Date().toISOString()
  }
}];

// N4 - Kimi Router (Asian Languages)
const input = $input.first().json;
const prevData = $('N2 - Preparador').first().json;
const isAsian = prevData.is_asian;

// Extract Claude's translation
let claudeTranslation = '';
try {
  claudeTranslation = input.content[0].text;
} catch(e) {
  claudeTranslation = JSON.stringify(input);
}

if (isAsian) {
  // For Asian languages, we could route to Kimi here
  // For now, Claude handles all and we pass through
  return [{
    json: {
      ...prevData,
      traducao_claude: claudeTranslation,
      modelo_usado: 'claude-sonnet-4',
      routed_to_kimi: false,
      note: 'Kimi integration available for ZH/JA/KO optimization'
    }
  }];
} else {
  return [{
    json: {
      ...prevData,
      traducao_claude: claudeTranslation,
      modelo_usado: 'claude-sonnet-4',
      routed_to_kimi: false
    }
  }];
}

