// N6 - Validador
const input = $input.first().json;
const prevData = $('N4 - Kimi Router').first().json;

// Extract Gemini's revision
let traducaoFinal = '';
try {
  traducaoFinal = input.candidates[0].content.parts[0].text;
} catch(e) {
  // Fallback to Claude translation if Gemini fails
  traducaoFinal = prevData.traducao_claude;
}

const original = prevData.texto_original;

// Validations
const validations = {
  lengthRatio: traducaoFinal.length / original.length,
  hasContent: traducaoFinal.length > 10,
  notTooShort: traducaoFinal.length > original.length * 0.5,
  notTooLong: traducaoFinal.length < original.length * 2.0,
  noEmptyResult: traducaoFinal.trim().length > 0
};

const isValid = Object.values(validations).every(v => v === true);

let warnings = [];
if (validations.lengthRatio < 0.7) warnings.push('Tradução possivelmente incompleta');
if (validations.lengthRatio > 1.5) warnings.push('Tradução possivelmente expandida demais');

return [{
  json: {
    traducao_final: traducaoFinal,
    traducao_claude: prevData.traducao_claude,
    idioma_destino: prevData.idioma_destino,
    variante: prevData.variante,
    autor: prevData.autor,
    obra: prevData.obra,
    capitulo: prevData.capitulo,
    gerar_capa: prevData.gerar_capa,
    modelo_principal: prevData.modelo_usado,
    validations,
    is_valid: isValid,
    warnings,
    timestamp: prevData.timestamp
  }
}];

// N7 - Learning Output + Response
const input = $input.first().json;

const metrics = {
  timestamp: input.timestamp,
  obra: input.obra,
  capitulo: input.capitulo,
  idioma: input.idioma_destino,
  modelo_principal: input.modelo_principal,
  length_original: (input.traducao_claude || '').length,
  length_final: input.traducao_final.length,
  is_valid: input.is_valid,
  warnings: input.warnings,
  quality_score: input.is_valid ? 0.9 : 0.5
};

// Log metrics (could write to file or DB)
console.log('METRICS:', JSON.stringify(metrics));

return [{
  json: {
    success: true,
    traducao: input.traducao_final,
    idioma: input.idioma_destino,
    obra: input.obra,
    autor: input.autor,
    capitulo: input.capitulo,
    modelo: input.modelo_principal,
    is_valid: input.is_valid,
    warnings: input.warnings,
    metrics
  }
}];

